mapper.select:
SELECT tshir.*
FROM esg.tb_safety_health_info_register tshir
WHERE tshir.comp_id = #{compId}
    AND tshir.write_year = #{writeYear}

    AND tshir.doc_type = #{docType}
    AND tshir.doc_no = #{docNo}

order by substring(tshir.receipt_dt, 1, 6) DESC, tshir.use_yn DESC, tshir.receipt_dt DESC

SELECT tshir.*
FROM esg.tb_safety_health_info_register tshir
WHERE tshir.comp_id = #{compId}
AND tshir.write_year = #{writeYear}
AND (tshir.hr_id = #{hrId} OR tshir.action_orgn_id = #{orgnId})

    AND tshir.doc_type = #{docType}
    AND tshir.doc_no = #{docNo}

order by substring(tshir.receipt_dt, 1, 6) DESC, tshir.use_yn DESC, tshir.receipt_dt DESC

mapper.update:
UPDATE esg.tb_safety_health_info_register
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}
